// utils/buffer.ts
function numArrayToBuffer(numArray) {
  return new Uint8Array(numArray).buffer;
}

// utils/broadcaster.ts
class BsocialBroadcaster {
  async broadcast(transaction3) {
    const response = await fetch(`${BSOCIAL_API_URL}/submit`, {
      method: "POST",
      headers: {
        "Content-Type": "application/octet-stream",
        "X-BSV-TOPIC": "tm_bsocial,tm_bap"
      },
      body: numArrayToBuffer(transaction3.toBEEF())
    });
    if (!response.ok) {
      return {
        status: "error",
        code: response.statusText,
        txid: transaction3.id("hex"),
        description: response.statusText
      };
    }
    return {
      status: "success",
      txid: transaction3.id("hex"),
      message: "Transaction broadcasted successfully"
    };
  }
}

class V5Broadcaster {
  async broadcast(transaction3) {
    const response = await fetch(`${V5_API_URL}/submit`, {
      method: "POST",
      headers: {
        "Content-Type": "application/octet-stream"
      },
      body: numArrayToBuffer(transaction3.toBinary())
    });
    const v5Response = await response.json();
    if (!response.ok) {
      return {
        status: "error",
        code: response.statusText,
        txid: transaction3.id("hex"),
        description: v5Response.error
      };
    }
    if (v5Response.success) {
      return {
        status: "success",
        txid: transaction3.id("hex"),
        message: "Transaction broadcasted successfully"
      };
    }
    return {
      status: "error",
      code: response.statusText,
      txid: transaction3.id("hex"),
      description: v5Response.error
    };
  }
}

