// tools/utils/aip.ts
var { toArray: toArray7, toBase64: toBase644, toUTF8: toUTF82 } = exports_utils;
async function signOpReturnWithAIP(dataArrays, signingKey, signingAddress) {
  let messageToSign = new Uint8Array;
  for (const data of dataArrays) {
    const temp = new Uint8Array(messageToSign.length + data.length);
    temp.set(messageToSign);
    temp.set(data, messageToSign.length);
    messageToSign = temp;
  }
  const signature = exports_BSM.sign(messageToSign, signingKey);
  const signatureBase64 = toBase644(signature.toCompact());
  const aipData = [
    toArray7("|", "utf8"),
    toArray7(AIP_PREFIX, "utf8"),
    toArray7("BITCOIN_ECDSA", "utf8"),
    toArray7(signingAddress, "utf8"),
    toArray7(signatureBase64, "utf8")
  ];
  return {
    signedData: [...dataArrays, ...aipData]
  };
}

