import { promises as fs3 } from "node:fs";
import path4 from "node:path";
var mintCollectionArgsSchema = exports_external.object({
  folderPath: exports_external.string().describe("Path to folder containing images to mint as a collection"),
  collectionName: exports_external.string().describe("Name of the collection"),
  description: exports_external.string().describe("Description of the collection"),
  rarityLabels: exports_external.array(exports_external.object({
    label: exports_external.string(),
    percentage: exports_external.number().min(0).max(100)
  })).optional().describe("Rarity labels and their percentages"),
  traits: exports_external.record(exports_external.array(exports_external.string())).optional().describe("Collection traits as key-value pairs where values are arrays of possible trait values"),
  skipBroadcast: exports_external.boolean().optional().describe("Skip broadcasting transactions (for testing)")
});
async function getImageFiles(folderPath) {
  const files = await fs3.readdir(folderPath);
  const imageFiles = [];
  const imageExtensions = [".jpg", ".jpeg", ".png", ".gif", ".webp", ".svg"];
  for (const file2 of files) {
    const filePath = path4.join(folderPath, file2);
    const stat = await fs3.stat(filePath);
    if (stat.isFile()) {
      const ext = path4.extname(file2).toLowerCase();
      if (imageExtensions.includes(ext)) {
        const data = await fs3.readFile(filePath);
        const contentType = {
          ".jpg": "image/jpeg",
          ".jpeg": "image/jpeg",
          ".png": "image/png",
          ".gif": "image/gif",
          ".webp": "image/webp",
          ".svg": "image/svg+xml"
        }[ext] || "application/octet-stream";
        imageFiles.push({
          path: filePath,
          name: path4.basename(file2, ext),
          data,
          contentType
        });
      }
    }
  }
  return imageFiles.sort((a3, b5) => a3.name.localeCompare(b5.name));
}
function generateItemTraits(itemIndex, collectionTraits) {
  const traits = [];
  if (collectionTraits) {
    for (const [traitName, possibleValues] of Object.entries(collectionTraits)) {
      if (possibleValues.length > 0) {
        const valueIndex = itemIndex % possibleValues.length;
        traits.push({
          name: traitName,
          value: possibleValues[valueIndex]
        });
      }
    }
  }
  return traits;
}
function registerMintCollectionTool(server, wallet4) {
  server.tool("wallet_mintCollection", "Mint a collection of ordinals from a folder of images with proper metadata. This tool creates a collection inscription first, then mints each image as a collection item with the appropriate metadata linking it to the collection.", { ...mintCollectionArgsSchema.shape }, async ({ folderPath, collectionName, description, rarityLabels, traits, skipBroadcast }) => {
    try {
      const paymentPk = wallet4.getPaymentKey();
      if (!paymentPk) {
        throw new Error("No payment key available in wallet");
      }
      const identityPk = wallet4.getIdentityKey();
      const imageFiles = await getImageFiles(folderPath);
      if (imageFiles.length === 0) {
        throw new Error("No image files found in the specified folder");
      }
      console.error(`Found ${imageFiles.length} images to mint`);
      const collectionSubTypeData = {
        description,
        quantity: imageFiles.length,
        rarityLabels: rarityLabels?.map((r10) => ({ label: r10.label })) || [],
        traits: traits ? Object.entries(traits).reduce((acc, [key, values]) => {
          acc[key] = {
            values,
            occurancePercentages: values.map(() => String(100 / values.length))
          };
          return acc;
        }, {}) : {}
      };
      const collectionMetadata = {
        app: "ord",
        type: "ord",
        subType: "collection",
        name: collectionName,
        subTypeData: collectionSubTypeData
      };
      const svgString = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100">
            <rect width="100" height="100" fill="#f0f0f0"/>
            <text x="50" y="55" text-anchor="middle" font-family="Arial" font-size="16">${collectionName}</text>
          </svg>`;
      const collectionIconData = exports_utils.toBase64(exports_utils.toArray(svgString, "utf8"));
      const walletAddress = paymentPk.toAddress().toString();
      const { paymentUtxos: collectionUtxos } = await wallet4.getUtxos();
      if (!collectionUtxos || collectionUtxos.length === 0) {
        throw new Error("No payment UTXOs available");
      }
      const collectionConfig = {
        utxos: collectionUtxos,
        destinations: [
          {
            address: walletAddress,
            inscription: {
              dataB64: collectionIconData,
              contentType: "image/svg+xml"
            }
          }
        ],
        paymentPk,
        changeAddress: walletAddress,
        metaData: collectionMetadata
      };
      if (identityPk) {
        collectionConfig.signer = { idKey: identityPk };
      }
      console.error("Creating collection inscription...");
      const collectionResult = await Q5(collectionConfig);
      let collectionTxid = "";
      const disableBroadcasting = skipBroadcast || process.env.DISABLE_BROADCASTING === "true";
      if (!disableBroadcasting) {
        const broadcaster = new V5Broadcaster;
        await collectionResult.tx.broadcast(broadcaster);
        collectionTxid = collectionResult.tx.id("hex");
        console.error(`✅ Collection created: ${collectionTxid}`);
        await wallet4.refreshUtxos();
      } else {
        collectionTxid = collectionResult.tx.id("hex");
        console.error(`\uD83D\uDD38 Collection created (not broadcast): ${collectionTxid}`);
      }
      const results = {
        collectionTxid,
        itemTxids: [],
        errors: [],
        totalCost: collectionResult.tx.getFee()
      };
      for (let i2 = 0;i2 < imageFiles.length; i2++) {
        const imageFile = imageFiles[i2];
        if (!imageFile)
          continue;
        console.error(`Minting item ${i2 + 1}/${imageFiles.length}: ${imageFile.name}`);
        try {
          const itemTraits = generateItemTraits(i2, traits);
          const itemSubTypeData = {
            collectionId: collectionTxid,
            mintNumber: i2 + 1,
            traits: itemTraits
          };
          if (rarityLabels && rarityLabels.length > 0) {
            const rarityIndex = Math.floor(i2 / imageFiles.length * rarityLabels.length);
            const rarityItem = rarityLabels[Math.min(rarityIndex, rarityLabels.length - 1)];
            if (rarityItem) {
              itemSubTypeData.rarityLabel = [
                { [rarityItem.label]: `${rarityItem.percentage}%` }
              ];
            }
          }
          const itemMetadata = {
            app: "ord",
            type: "ord",
            subType: "collectionItem",
            name: imageFile.name,
            subTypeData: itemSubTypeData
          };
          const { paymentUtxos: itemUtxos } = await wallet4.getUtxos();
          if (!itemUtxos || itemUtxos.length === 0) {
            throw new Error("No payment UTXOs available for item");
          }
          const itemConfig = {
            utxos: itemUtxos,
            destinations: [
              {
                address: walletAddress,
                inscription: {
                  dataB64: exports_utils.toBase64(Array.from(imageFile.data)),
                  contentType: imageFile.contentType
                }
              }
            ],
            paymentPk,
            changeAddress: walletAddress,
            metaData: itemMetadata
          };
          if (identityPk) {
            itemConfig.signer = { idKey: identityPk };
          }
          const itemResult = await Q5(itemConfig);
          if (!disableBroadcasting) {
            const broadcaster = new V5Broadcaster;
            await itemResult.tx.broadcast(broadcaster);
            const itemTxid = itemResult.tx.id("hex");
            results.itemTxids.push(itemTxid);
            console.error(`  ✅ Item minted: ${itemTxid}`);
            await wallet4.refreshUtxos();
          } else {
            const itemTxid = itemResult.tx.id("hex");
            results.itemTxids.push(itemTxid);
            console.error(`  \uD83D\uDD38 Item minted (not broadcast): ${itemTxid}`);
          }
          results.totalCost += itemResult.tx.getFee();
        } catch (error48) {
          const errorMessage = error48 instanceof Error ? error48.message : String(error48);
          results.errors.push({ file: imageFile.name, error: errorMessage });
          console.error(`  ❌ Failed to mint ${imageFile.name}: ${errorMessage}`);
        }
      }
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              success: true,
              collectionTxid: results.collectionTxid,
              itemsMinted: results.itemTxids.length,
              totalItems: imageFiles.length,
              errors: results.errors,
              totalCost: results.totalCost,
              summary: `Collection "${collectionName}" created with ${results.itemTxids.length}/${imageFiles.length} items successfully minted.${results.errors.length > 0 ? ` ${results.errors.length} items failed.` : ""}`
            }, null, 2)
          }
        ]
      };
    } catch (error48) {
      const errorMessage = error48 instanceof Error ? error48.message : String(error48);
      return {
        content: [
          {
            type: "text",
            text: `Error minting collection: ${errorMessage}`
          }
        ],
        isError: true
      };
    }
  });
}

