// tools/wallet/purchaseListing.ts
function registerPurchaseListingTool(server, wallet4) {
  server.tool("wallet_purchaseListing", "Purchases a listing from the Bitcoin SV ordinals marketplace. Supports both NFT purchases (with royalty payments to original creators) and BSV-20/BSV-21 token purchases. The tool handles all aspects of the transaction - from fetching listing details, calculating fees, creating and broadcasting the transaction.", { ...purchaseListingArgsSchema.shape }, async ({ listingOutpoint, ordAddress, listingType, tokenProtocol, tokenID, description }) => {
    try {
      const identityKeyWif = process.env.IDENTITY_KEY_WIF;
      let identityPk;
      if (identityKeyWif) {
        try {
          identityPk = PrivateKey.fromWif(identityKeyWif);
        } catch (e) {
          console.warn("Warning: Invalid IDENTITY_KEY_WIF environment variable; sigma signing disabled", e);
        }
      }
      const response = await fetch(`https://ordinals.gorillapool.io/api/txos/${listingOutpoint}?script=true`);
      if (!response.ok) {
        throw new Error(`Failed to fetch listing data: ${response.statusText}`);
      }
      const listingData = await response.json();
      if (!listingData.data?.list?.price) {
        throw new Error("Listing is either not for sale or invalid");
      }
      if (!listingData.data.list.payout) {
        throw new Error("Listing doesn't have payout information");
      }
      const listingPrice = listingData.data.list.price;
      let marketFee = Math.round(listingPrice * MARKET_FEE_PERCENTAGE);
      if (marketFee < MINIMUM_MARKET_FEE_SATOSHIS) {
        marketFee = MINIMUM_MARKET_FEE_SATOSHIS;
      }
      const [txid, voutStr] = listingOutpoint.split("_");
      if (!txid) {
        throw new Error("Invalid outpoint format. Expected txid_vout");
      }
      const vout = Number.parseInt(voutStr || "0", 10);
      const paymentPk = wallet4.getPrivateKey();
      if (!paymentPk) {
        throw new Error("No private key available in wallet");
      }
      const paymentAddress = paymentPk.toAddress().toString();
      const { paymentUtxos } = await wallet4.getUtxos();
      if (!paymentUtxos || paymentUtxos.length === 0) {
        throw new Error(`No payment UTXOs available for address ${paymentAddress}. 
Please fund this wallet address with enough BSV to cover the purchase price 
(${listingData.data.list.price} satoshis) plus market fee (${marketFee} satoshis) and transaction fees.`);
      }
      const additionalPayments = [
        {
          to: MARKET_WALLET_ADDRESS,
          amount: marketFee
        }
      ];
      const metaData = {
        app: "bsv-mcp",
        type: "ord",
        op: "purchase"
      };
      let transaction4;
      if (listingType === "token") {
        if (!tokenProtocol) {
          throw new Error("tokenProtocol is required for token listings");
        }
        if (!tokenID) {
          throw new Error("tokenID is required for token listings");
        }
        if (!listingData.data.bsv20) {
          throw new Error("This is not a valid BSV-20 token listing");
        }
        if (!listingData.data.bsv20.amt) {
          throw new Error("Token listing doesn't have an amount specified");
        }
        const protocol = tokenProtocol === "bsv-20" ? h22.BSV20 : h22.BSV21;
        const listingUtxo = {
          txid,
          vout,
          script: listingData.script,
          satoshis: 1,
          amt: listingData.data.bsv20.amt,
          id: tokenID,
          payout: listingData.data.list.payout
        };
        transaction4 = await I5({
          protocol,
          tokenID,
          utxos: paymentUtxos,
          paymentPk,
          listingUtxo,
          ordAddress,
          additionalPayments,
          metaData
        });
      } else {
        const listingUtxo = {
          txid,
          vout,
          script: listingData.script,
          satoshis: listingData.satoshis
        };
        const listing = {
          payout: listingData.data.list.payout,
          listingUtxo
        };
        let royalties = [];
        if (listingData.origin?.data?.map?.royalties) {
          try {
            royalties = JSON.parse(listingData.origin.data.map.royalties);
          } catch (error48) {}
        }
        const purchaseOrdListingConfig = {
          utxos: paymentUtxos,
          paymentPk,
          ordAddress,
          listing,
          additionalPayments,
          metaData,
          royalties
        };
        transaction4 = await C5(purchaseOrdListingConfig);
      }
      try {
        await wallet4.refreshUtxos();
      } catch (refreshError) {}
      const disableBroadcasting = process.env.DISABLE_BROADCASTING === "true";
      if (!disableBroadcasting) {
        const broadcastResult = await transaction4.tx.broadcast(Bz());
        const resultStatus = typeof broadcastResult === "object" && "status" in broadcastResult ? broadcastResult.status : "unknown";
        const resultMessage = typeof broadcastResult === "object" && "error" in broadcastResult ? broadcastResult.error : "Transaction broadcast successful";
        return {
          content: [
            {
              type: "text",
              text: JSON.stringify({
                status: resultStatus,
                message: resultMessage,
                txid: transaction4.tx.id("hex"),
                listingOutpoint,
                destinationAddress: ordAddress,
                listingType,
                tokenProtocol: tokenID ? tokenProtocol : undefined,
                tokenID,
                price: listingData.data.list.price,
                marketFee,
                marketFeeAddress: MARKET_WALLET_ADDRESS,
                royaltiesPaid: listingType === "nft" && listingData.origin?.data?.map?.royalties ? JSON.parse(listingData.origin.data.map.royalties) : undefined
              })
            }
          ]
        };
      }
      return {
        content: [
          {
            type: "text",
            text: transaction4.tx.toHex()
          }
        ]
      };
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      return { content: [{ type: "text", text: msg }], isError: true };
    }
  });
}

// tools/wallet/refreshUtxos.ts
function registerRefreshUtxosTool(server, wallet4) {
  server.tool("wallet_refreshUtxos", "Refreshes and returns the wallet's UTXOs. This is useful for debugging UTXO issues, ensuring the wallet has the latest transaction outputs, and for verifying available funds before making transactions.", {}, async () => {
    try {
      await wallet4.refreshUtxos();
      const { paymentUtxos, nftUtxos } = await wallet4.getUtxos();
      const totalSatoshis = paymentUtxos.reduce((sum, utxo) => sum + utxo.satoshis, 0);
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              status: "success",
              paymentUtxos: paymentUtxos.map((utxo) => ({
                txid: utxo.txid,
                vout: utxo.vout,
                satoshis: utxo.satoshis,
                outpoint: `${utxo.txid}_${utxo.vout}`
              })),
              nftUtxos: nftUtxos.map((utxo) => ({
                txid: utxo.txid,
                vout: utxo.vout,
                origin: utxo.origin,
                outpoint: `${utxo.txid}_${utxo.vout}`
              })),
              totalPaymentUtxos: paymentUtxos.length,
              totalNftUtxos: nftUtxos.length,
              totalSatoshis,
              totalBsv: X3(totalSatoshis)
            }, null, 2)
          }
        ]
      };
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      return { content: [{ type: "text", text: msg }], isError: true };
    }
  });
}

// tools/wallet/sendToAddress.ts
function registerSendToAddressTool(server, wallet4) {
  server.tool("wallet_sendToAddress", "Sends Bitcoin SV (BSV) to a specified address. This tool supports payments in both BSV and USD amounts (with automatic conversion using current exchange rates). Transaction fees are automatically calculated and a confirmation with transaction ID is returned upon success.", { ...sendToAddressArgsSchema.shape }, async ({ address, amount, currency = "BSV", description = "Send to address" }) => {
    try {
      let satoshis;
      if (currency === "USD") {
        const bsvPriceUsd = await getBsvPriceWithCache2();
        const bsvAmount = amount / bsvPriceUsd;
        satoshis = W2(bsvAmount);
      } else {
        satoshis = W2(amount);
      }
      const lockingScript = new P2PKH().lock(address);
      const tx = await wallet4.createAction({
        description,
        outputs: [
          {
            lockingScript: lockingScript.toHex(),
            satoshis,
            outputDescription: `Payment to ${address}`
          }
        ]
      });
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              status: "success",
              txid: tx.txid,
              satoshis
            })
          }
        ]
      };
    } catch (error48) {
      return {
        content: [
          {
            type: "text",
            text: error48 instanceof Error ? error48.message : String(error48)
          }
        ],
        isError: true
      };
    }
  });
}

